class Solution {
public:
    int romanToInt(string s) {
        int n = s.size();
        unordered_map<char, int> myHashMap = {
            {'I', 1}, 
            {'V', 5}, 
            {'X', 10}, 
            {'L', 50}, 
            {'C', 100}, 
            {'D', 500}, 
            {'M', 1000}
        };

        int total = 0;
        int max_num = myHashMap[s[n-1]];
        for(int c = n-1; c >= 0; c--){
            int temp = myHashMap[s[c]];
            if(max_num <= temp){
                total += temp;
            } else{
                total -= temp;
            }
            max_num = (max_num, temp);
        }

        return total;



    }
};

class Solution {

public:
    int char_toint(char c){
        switch(c){
            case 'I':
                return 1;
            case 'V':
                return 5;
            case 'X':
                return 10;
            case 'L':
                return 50;
            case 'C':
                return 100;
            case 'D':
                return 500;
            case 'M':
                return 1000;
        }
        return 0;

    }
    int romanToInt(string s) {
        int n = s.size();

        int total = 0;
        int max_num = char_toint(s[n-1]);
        for(int c = n-1; c >= 0; c--){
            int temp = char_toint(s[c]);


            if(max_num <= temp){
                total += temp;
            } else{
                total -= temp;
            }
            max_num = (max_num, temp);
        }

        return total;

    }
};
